// Sticker Quest design tokens per category / bonus item.
// `art` names a PNG in /public/art (generated by scripts/generate-art.mjs);
// StickerArt falls back to `emoji` when the PNG isn't there.

export interface CategoryTheme {
  main: string;
  edge: string;
  soft: string;
  text: string;
  btn: string;
  art: string;
  emoji: string;
}

