export const fallbackTheme: CategoryTheme = {
  main: '#FFB020',
  edge: '#D98F00',
  soft: '#FFF4D9',
  text: '#8A5B00',
  btn: 'btn-sun',
  art: 'mascot',
  emoji: '⭐',
};

export function getCategoryTheme(id: string): CategoryTheme {
  return categoryTheme[id] ?? fallbackTheme;
}

